这是经典的 Lomuto 分区方案，原地排序，空间 O(log n)（递归栈）：

```javascript
/**
 * 快速排序（Lomuto 分区，原地排序）
 * @param {number[]} arr
 * @param {number}   low
 * @param {number}   high
 * @returns {number[]} 排序后的原数组
 */
function quickSort(arr, low = 0, high = arr.length - 1) {
  if (low >= high) return arr;

  const pivotIdx = partition(arr, low, high);
  quickSort(arr, low, pivotIdx - 1);
  quickSort(arr, pivotIdx + 1, high);
  return arr;
}

function partition(arr, low, high) {
  const pivot = arr[high];       // 选最右元素为基准
  let i = low - 1;               // i 指向小于 pivot 的区域的末尾

  for (let j = low; j < high; j++) {
    if (arr[j] <= pivot) {
      i++;
      [arr[i], arr[j]] = [arr[j], arr[i]];  // ES6 解构交换
    }
  }
  // 把 pivot 放到正确位置
  [arr[i + 1], arr[high]] = [arr[high], arr[i + 1]];
  return i + 1;
}

// ── 测试 ──
const test = [3, 6, 8, 10, 1, 2, 1];
console.log(quickSort([...test])); // [1, 1, 2, 3, 6, 8, 10]
```

